  ('social-worker-moex-00002', 'social-worker', 'social-worker-moex-114-0e79f916', 'sub-social-worker-01', NULL, 'essay', '親職教育重視嬰幼兒氣質和管教原則之間的「契合度（適配度）」
（goodnessoffit），生態系統理論強調環境和人之間的互動關係能夠達到
「契合度」，試舉例說明並比較這兩種契合度的意涵。（25分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:00+00:00", "source_pdf_sha1": "461402c5eeb6", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "114030", "c": "103", "s": "0305", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "人類行為與社會環境", "year": "114", "exam_name": "114年第一次專技人員高等考試營養師、護理師、社會工作師考試", "original_question_number": "二", "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-00003', 'social-worker', 'social-worker-moex-114-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '有關柯爾堡（L.Kohlberg）和吉利根（K.Gilligan）道德發展理論的敘述，下列何者錯誤？', '["柯爾堡（L.Kohlberg）理論主要立基於公平正義的觀點，強調個體可以獨立地做出道德判斷", "柯爾堡（L.Kohlberg）批評吉利根（K.Gilligan）道德兩難的情境設計太過抽象，無法說明女性 的思考", "吉利根（K.Gilligan）與其同事主張，女性道德發展來自對重要他人的承諾，強調善良犧牲和仁慈", "吉利根（K.Gilligan）稱女性道德發展具有個人生存取向、以自我犧牲為美德、非暴力的道德責 任三個層次"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:00+00:00", "source_pdf_sha1": "461402c5eeb6", "answer_pdf_sha1": "97eeea6c0c9c", "source_family": "moex-gov-tw", "moex": {"exam_code": "114030", "c": "103", "s": "0305", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "人類行為與社會環境", "year": "114", "exam_name": "114年第一次專技人員高等考試營養師、護理師、社會工作師考試", "original_question_number": 1, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-00004', 'social-worker', 'social-worker-moex-114-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '兒童總是要抱著他那不能洗、不能曬、不能忘記帶的小被被才能安然入睡。依Winnicott說法，這 床被稱之為：', '["過渡性客體（transitionalobject）", "一般性客體（generalobject）", "互為性客體（interobjectivity）", "交互性主體（intersubjectivity）"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:00+00:00", "source_pdf_sha1": "461402c5eeb6", "answer_pdf_sha1": "97eeea6c0c9c", "source_family": "moex-gov-tw", "moex": {"exam_code": "114030", "c": "103", "s": "0305", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "人類行為與社會環境", "year": "114", "exam_name": "114年第一次專技人員高等考試營養師、護理師、社會工作師考試", "original_question_number": 2, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-00005', 'social-worker', 'social-worker-moex-114-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', 'SigmundFreud人格發展理論聚焦於性心理的發展，並分為五個關鍵時期。下列敘述何者錯誤？', '["口腔期（oralstage），嬰兒透過進食時的吸吮、咀嚼、吞嚥獲得滿足，注意力是在獲得和接受", "肛門期（analstage），排泄訓練是此時期的重要課題，注意力著重在讚美和批評", "性蕾期（phallicstage），小孩會不自覺地碰觸生殖器官，或看別人的身體，注意力是在愛與被愛", "潛伏期（latencystage），開始發展超我，性慾尚未被激起，注意力放在功課與學校活動"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:00+00:00", "source_pdf_sha1": "461402c5eeb6", "answer_pdf_sha1": "97eeea6c0c9c", "source_family": "moex-gov-tw", "moex": {"exam_code": "114030", "c": "103", "s": "0305", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "人類行為與社會環境", "year": "114", "exam_name": "114年第一次專技人員高等考試營養師、護理師、社會工作師考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-00006', 'social-worker', 'social-worker-moex-114-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '個案表示渴望重返青春，在意自己對異性不具吸引力，以 Erikson 的心理社會階段來看，此人正 處在何種發展任務與危機？', '["自我認同vs.認同混淆（Identityvs.RoleConfusion）", "親密vs.孤立（Intimacyvs.Isolation）", "生產力vs.停滯（Generativityvs.Stagnation）", "統整vs.絕望（EgoIntegrityvs.Despair）"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:00+00:00", "source_pdf_sha1": "461402c5eeb6", "answer_pdf_sha1": "97eeea6c0c9c", "source_family": "moex-gov-tw", "moex": {"exam_code": "114030", "c": "103", "s": "0305", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "人類行為與社會環境", "year": "114", "exam_name": "114年第一次專技人員高等考試營養師、護理師、社會工作師考試", "original_question_number": 4, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-00007', 'social-worker', 'social-worker-moex-114-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '某甲是一位家管，最近被診斷出罹患嚴重疾病，治療一段時間後，醫生建議需要長期照護，家中 還有兩位目前就讀高中的兒女，某甲的配偶原本自己照顧某甲，但又因經濟與自己健康因素，後 來與家人求助由親戚、自己與兒女輪流照顧某甲，而兒女們願意開始分擔家務，也慢慢能接受某 甲生重病，甚至可能永遠無法恢復健康，某甲配偶感受到與兒女們的關係更緊密。若以McCubbin 與Patterson提出的雙重家庭壓力理論（DoubleABC-X）模式來分析此案例，下列何者錯誤？', '["aA指壓力事件：某甲生重病", "bB 指家庭已有的或為因應壓力而擴張的資源：某甲配偶求助親戚與兒女，輪流照顧某甲、分 擔家務", "cC 指對前次事件危機、現存及新開發資源的界定：兒女接受某甲生重病且可能無法恢復健康 的事實，家人間彼此幫忙，家庭凝聚力也提升了", "xX指家庭因應壓力的調適：家人採取因應措施，調適狀況良好"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:00+00:00", "source_pdf_sha1": "461402c5eeb6", "answer_pdf_sha1": "97eeea6c0c9c", "source_family": "moex-gov-tw", "moex": {"exam_code": "114030", "c": "103", "s": "0305", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "人類行為與社會環境", "year": "114", "exam_name": "114年第一次專技人員高等考試營養師、護理師、社會工作師考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-00008', 'social-worker', 'social-worker-moex-114-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '有關家庭生命週期，下列敘述何者正確？', '["雖然現今家庭形式多元，但家庭仍嚴格遵守家庭生命週期從某階段進展到下一階段", "晚期的家庭生活代表家庭生命週期結束", "生命週期的轉折易出現家庭壓力", "分居、離婚與再婚家庭並不影響家庭生命週期"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:00+00:00", "source_pdf_sha1": "461402c5eeb6", "answer_pdf_sha1": "97eeea6c0c9c", "source_family": "moex-gov-tw", "moex": {"exam_code": "114030", "c": "103", "s": "0305", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "人類行為與社會環境", "year": "114", "exam_name": "114年第一次專技人員高等考試營養師、護理師、社會工作師考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-00009', 'social-worker', 'social-worker-moex-114-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '有關學齡期兒童階段的發展任務，下列敘述何者正確？', '["Freud：性本能衝動支配力增強、超我減弱", "Erikson：自我創新發展能力增長；引發稱職感或無能感", "Piaget：抽象的邏輯推理層次；理解物質存在不變的原則", "Kohlberg：依照外在的懲罰或報酬來推理，進而依習俗法規類推並考量外界意見"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:00+00:00", "source_pdf_sha1": "461402c5eeb6", "answer_pdf_sha1": "97eeea6c0c9c", "source_family": "moex-gov-tw", "moex": {"exam_code": "114030", "c": "103", "s": "0305", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "人類行為與社會環境", "year": "114", "exam_name": "114年第一次專技人員高等考試營養師、護理師、社會工作師考試", "original_question_number": 7, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-00010', 'social-worker', 'social-worker-moex-114-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '不同理論各有其適用的情境，有關各理論的描述，下列何者錯誤？', '["女性主義挑戰社會習慣的二分法，如何對人造成限制和壓迫", "符號互動論聚焦於宏觀因素", "功能論解釋社會制度和組織如何讓整體社會維持穩定", "衝突理論解釋街頭抗議、遊行如何能促成社會福祉的積極改變"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:00+00:00", "source_pdf_sha1": "461402c5eeb6", "answer_pdf_sha1": "97eeea6c0c9c", "source_family": "moex-gov-tw", "moex": {"exam_code": "114030", "c": "103", "s": "0305", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "人類行為與社會環境", "year": "114", "exam_name": "114年第一次專技人員高等考試營養師、護理師、社會工作師考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL)
